// Parse incoming CRM event
const body = $json["body"] || {};

// Validate required fields
if (!body.eventType || !body.entityId || !body.entityType) {
  throw new Error('Missing required fields: eventType, entityId, entityType');
}

return [{ json: {
  eventType: body.eventType,
  entityId: body.entityId,
  entityType: body.entityType,
  timestamp: body.timestamp || new Date().toISOString(),
  rawData: body,
  metadata: body.metadata || {}
} }];

// Fetch entity details from CRM API
const { entityType, entityId } = $json;
const baseUrl = 'http://host.docker.internal:5000/api';

// Map entity type to API endpoint
const endpointMap = {
  'customer': '/customers',
  'property': '/properties',
  'deal': '/deals',
  'agent': '/agents',
  'task': '/tasks'
};

const endpoint = endpointMap[entityType] || `/${entityType}`;
const url = `${baseUrl}${endpoint}/${entityId}`;

return [{ json: {
  ...$json,
  crmApiUrl: url
} }];

// Determine notification recipients and message based on event type
const { eventType, entityType, entityId, rawData } = $json;
const entityData = $json[0] || {}; // From HTTP Request node

let recipients = [];
let subject = '';
let message = '';

switch (eventType) {
  case 'lead_created':
    // New lead notification - notify assigned agent and sales manager
    subject = `New Lead: ${entityData.first_name || ''} ${entityData.last_name || ''}`;
    message = `A new lead has been captured:\n\n` +
              `Name: ${entityData.first_name || ''} ${entityData.last_name || ''}\n` +
              `Email: ${entityData.email || 'N/A'}\n` +
              `Phone: ${entityData.phone || 'N/A'}\n` +
              `Interest: ${entityData.property_interest || 'Not specified'}\n` +
              `Source: ${entityData.source || 'Website'}\n\n` +
              `Please follow up within 24 hours.`;

    // In real implementation, you'd query for assigned agent
    // For demo, we'll notify a default agent and manager
    recipients = [
      { id: 'agent_001', type: 'agent', name: 'Sales Agent', email: 'agent@company.com', phone: '+15551234567', slack: 'UAGENT001' },
      { id: 'mgr_001', type: 'manager', name: 'Sales Manager', email: 'manager@company.com', phone: '+15559876543', slack: 'UMGR001' }
    ];
    break;

  case 'property_updated':
    // Property update notification - notify interested buyers
    subject = `Property Update: ${entityData.address || 'Property'} #${entityId}`;
    message = `A property you're interested in has been updated:\n\n` +
              `Address: ${entityData.address || 'N/A'}\n` +
              `Price: $${(entityData.price || 0).toLocaleString()}\n` +
              `Beds/Baths: ${entityData.bedrooms || 'N/A'}/${entityData.bathrooms || 'N/A'}\n` +
              `Square Feet: ${(entityData.square_feet || 0).toLocaleString()} sq ft\n` +
              `Last Updated: ${new Date(entityData.updated_at || Date.now()).toLocaleString()}\n\n` +
              `View details in your portal.`;

    // In real implementation, you'd query for customers interested in this property
    // For demo, we'll simulate interested parties
    recipients = [
      { id: 'cust_001', type: 'customer', name: 'John Doe', email: 'john@example.com', phone: '+15551111111', slack: 'U1' },
      { id: 'cust_002', type: 'customer', name: 'Jane Smith', email: 'jane@example.com', phone: '+15552222222', slack: 'U2' }
    ];
    break;

  case 'deal_stage_changed':
    // Deal stage change - notify agent and client
    const oldStage = req.body.old_stage || 'Unknown';
    const newStage = req.body.new_stage || 'Unknown';

    subject = `Deal Stage Changed: ${entityData.title || 'Deal'} #${entityId}`;
    message = `A deal's stage has been updated:\n\n` +
              `Deal: ${entityData.title || 'N/A'}\n` +
              `Property: ${entityData.property_address || 'N/A'}\n` +
              `Client: ${entityData.client_name || 'N/A'}\n` +
              `Stage Changed: ${oldStage} → ${newStage}\n` +
              `Expected Close: ${entityData.expected_close_date || 'Not set'}\n\n` +
              `Please review and take appropriate action.`;

    recipients = [
      { id: entityData.agent_id || 'agent_001', type: 'agent', name: 'Assigned Agent', email: 'agent@company.com', phone: '+15551234567', slack: 'UAGENT001' },
      { id: entityData.client_id || 'cust_003', type: 'customer', name: 'Client', email: 'client@example.com', phone: '+15553333333', slack: 'U3' }
    ];
    break;

  default:
    // Generic notification
    subject = `${entityType.charAt(0).toUpperCase() + entityType.slice(1)} Event: ${eventType}`;
    message = `A ${eventType} event occurred for ${entityType} #${entityId} at ${new Date().toLocaleString()}.\n\nDetails:${JSON.stringify(entityData, null, 2)}`;

    // Notify admins for unknown event types
    recipients = [
      { id: 'admin_001', type: 'admin', name: 'System Admin', email: 'admin@company.com', phone: '+15550000000', slack: 'UADMIN001' }
    ];
}

// Filter out recipients with missing contact info
const validRecipients = recipients.filter(r => 
  (r.email && r.email.includes('@')) || 
  (r.phone && /^\+?[1-9]\d{1,14}$/.test(r.phone.replace(/[^\d+]/g, ''))) ||
  (r.slack && /^U[A-Z0-9]+$/.test(r.slack))
);

return [{ json: {
  eventType,
  entityType,
  entityId,
  subject,
  message,
  recipients: validRecipients,
  timestamp: new Date().toISOString(),
  metadata: {
    ...$json.metadata,
    processedAt: new Date().toISOString(),
    originalEvent: rawData
  }
} }];

// Prepare notifications for each recipient
const { subject, message, recipients } = $json;

// We'll split this out to send to each recipient via the multi-channel hub
// For now, return array of notifications to send
const notifications = recipients.map(recipient => ({
  recipientId: recipient.id,
  recipientType: recipient.type,
  subject: subject,
  message: message,
  channels: ['email', 'sms', 'slack'], // Send via all three channels
  priority: 'normal',
  metadata: {
    ...$json.metadata,
    recipientName: recipient.name,
    recipientEmail: recipient.email,
    recipientPhone: recipient.phone,
    recipientSlack: recipient.slack
  }
}));

return [{ json: { notifications } }];
